import{c as t,Q as r,j as a,m as s}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse(`{"title":"90% of CLAUDE USERS still don't know these repos exist — @0x_kaize","description":"","frontmatter":{"title":"90% of CLAUDE USERS still don't know these repos exist — @0x_kaize","author":"kaize（@0x_kaize）","date":"2026-04-19T00:00:00.000Z","source":"https://x.com/0x_kaize/status/2045828061640245608","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-19-@0x_kaize-245608.md","filePath":"research/tweets/2026-04-19-@0x_kaize-245608.md","lastUpdated":1779894392000}`),o={name:"research/tweets/2026-04-19-@0x_kaize-245608.md"};function i(l,e,n,p,d,c){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="_90-of-claude-users-still-don-t-know-these-repos-exist-—-0x-kaize" tabindex="-1">90% of CLAUDE USERS still don&#39;t know these repos exist — @0x_kaize <a class="header-anchor" href="#_90-of-claude-users-still-don-t-know-these-repos-exist-—-0x-kaize" aria-label="Permalink to &quot;90% of CLAUDE USERS still don&#39;t know these repos exist — @0x_kaize&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/0x_kaize/status/2045828061640245608" target="_blank" rel="noreferrer">https://x.com/0x_kaize/status/2045828061640245608</a><strong>作者</strong>：kaize（@0x_kaize） <strong>發布日期</strong>：2026-04-19 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：推文（Note Tweet） <strong>統計</strong>：144 likes · 18 retweets · 166 bookmarks · 15627 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>90% of CLAUDE USERS still don&#39;t know these repos exist</p><p>week 2 of digging through github</p><p>here are 10 MORE Claude Code repos that will rewire your workflow:</p><p>1/ anthropics/claude-code</p><p>The official Claude Code repo - the agentic coding tool that lives in your terminal</p><ul><li>55k+ stars</li><li>understands your codebase via natural language commands</li><li>maintained directly by Anthropic</li></ul><p>repo: <a href="https://github.com/anthropics/claude-code" target="_blank" rel="noreferrer">https://github.com/anthropics/claude-code</a></p><p>2/ anthropics/skills</p><p>Official Anthropic public repository of Agent Skills</p><ul><li>37.5k+ stars</li><li>PDF, DOCX, XLSX, PPTX manipulation + art generation</li><li>canonical reference for how to author skills</li></ul><p>repo: <a href="https://github.com/anthropics/skills" target="_blank" rel="noreferrer">https://github.com/anthropics/skills</a></p><p>3/ everything-claude-code</p><p>Hackathon-winning harness built from 10+ months of daily use</p><ul><li>30 agents, 136 skills, 60 slash commands, 14 MCP configs</li><li>1282 tests, 98% coverage, 102 static analysis rules</li><li>winner of Cerebral Valley x Anthropic hackathon</li></ul><p>repo: <a href="https://github.com/affaan-m/everything-claude-code" target="_blank" rel="noreferrer">https://github.com/affaan-m/everything-claude-code</a></p><p>4/ claude-code-system-prompts</p><p>All Claude Code system prompts, updated within minutes of each release</p><ul><li>24 builtin tool descriptions + ~40 system reminders</li><li>sub-agent prompts (Plan/Explore/Task)</li><li>CHANGELOG across 155+ versions</li></ul><p>repo: <a href="https://github.com/Piebald-AI/claude-code-system-prompts" target="_blank" rel="noreferrer">https://github.com/Piebald-AI/claude-code-system-prompts</a></p><p>5/ Repomix</p><p>Pack your entire codebase into one AI-readable file</p><ul><li>20.9k+ stars</li><li>perfect for feeding big repos into Claude&#39;s context</li><li>multiple output formats (XML, Markdown, plain)</li></ul><p>repo: <a href="https://github.com/yamadashy/repomix" target="_blank" rel="noreferrer">https://github.com/yamadashy/repomix</a></p><p>6/ agents (wshobson)</p><p>Massive collection of production-ready subagents</p><ul><li>25k+ stars</li><li>covers strategy, dev, security, design, data, research</li><li>drop-in for Claude Code workflows</li></ul><p>repo: <a href="https://github.com/wshobson/agents" target="_blank" rel="noreferrer">https://github.com/wshobson/agents</a></p><p>7/ graphify</p><p>Turn any codebase or knowledge base into an interactive knowledge graph</p><ul><li>explore, search, ask questions</li><li>works with Claude Code, Codex, Cursor, Copilot, Gemini CLI</li><li>insane for onboarding into big repos</li></ul><p>repo: <a href="https://github.com/safishamsi/graphify" target="_blank" rel="noreferrer">https://github.com/safishamsi/graphify</a></p><p>8/ claude-squad</p><p>Terminal multiplexer for AI coding agents</p><ul><li>5.6k+ stars</li><li>manages Claude Code, Aider, Codex, OpenCode, Amp in one UI</li><li>parallel agents without the chaos</li></ul><p>repo: <a href="https://github.com/smtg-ai/claude-squad" target="_blank" rel="noreferrer">https://github.com/smtg-ai/claude-squad</a></p><p>9/ claude-mem</p><p>Long-term memory for Claude Code via compression</p><ul><li>persists context between sessions</li><li>lightweight and composable</li><li>fixes the #1 thing everyone complains about</li></ul><p>repo: <a href="https://github.com/thedotmack/claude-mem" target="_blank" rel="noreferrer">https://github.com/thedotmack/claude-mem</a></p><p>10/ claude-code-security-review</p><p>AI-powered security review GitHub Action</p><ul><li>2.8k+ stars</li><li>Claude analyzes PR diffs for vulnerabilities</li><li>drop-in CI/CD integration, 5 min to set up</li></ul><p>repo: <a href="https://github.com/anthropics/claude-code-security-review" target="_blank" rel="noreferrer">https://github.com/anthropics/claude-code-security-review</a></p><p>that&#39;s 20 repos down, 27+ still in my backlog, part 3 soon</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：精選 10 個 Claude Code 生態系 GitHub repos，涵蓋官方工具、skills 庫、subagent 集合、記憶持久化與安全審查自動化。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>官方資源值得直接採用</strong>：anthropics/claude-code（55k+ stars）與 anthropics/skills（37.5k+ stars）是 skill authoring 的 canonical reference，多數 workspace 建設可直接對照。</li><li><strong>everything-claude-code 是工程化最完整的 harness</strong>：30 agents、136 skills、60 slash commands、1282 tests、98% coverage，是衡量自建 workspace 規模的基準線。</li><li><strong>claude-code-system-prompts 提供版本追蹤</strong>：155+ 版本 CHANGELOG，可用於逆向了解 Anthropic 內部 sub-agent prompts 演進，對 workspace 調校有參考價值。</li><li><strong>Repomix 解決大型 codebase 餵入問題</strong>：支援 XML/Markdown/plain 輸出，適合將整個 repo 打包進 context，與 researcher sub-agent 搭配使用。</li><li><strong>claude-mem 補足跨 session 記憶缺口</strong>：透過壓縮持久化 context，定位與 Auto Memory 互補（而非替代）。</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>anthropics/claude-code：55k+ stars</li><li>anthropics/skills：37.5k+ stars</li><li>everything-claude-code：30 agents、136 skills、1282 tests、98% coverage</li><li>Repomix：20.9k+ stars</li><li>wshobson/agents：25k+ stars</li><li>claude-squad：5.6k+ stars</li><li>claude-code-security-review：2.8k+ stars</li><li>系列推文第 2 篇，backlog 尚有 27+ repos</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>列表型內容，缺乏實際評測</strong>：所有 star 數與描述均為作者整理，未提供使用心得或 benchmark，無法判斷哪些 repos 實際成熟可用（例如 graphify 無 star 數，claude-mem 無說明壓縮策略）。</li><li><strong>everything-claude-code 數字驚人但存疑</strong>：136 skills + 1282 tests 若屬實，是業界少見的工程化成果；但 hackathon 背景與長期維護品質通常有落差，引入前需評估 dependency 與更新頻率。</li><li><strong>對 cc-workspace 用戶的實際應用價值</strong>：anthropics/skills 與 claude-code-system-prompts 最直接有參考價值——前者可比對 skill authoring pattern，後者可追蹤 sub-agent prompt 演進；其餘 repos 多為可選參考。</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>6/10</td><td>anthropics/skills 和 system-prompts 可直接參照，但列表本身無法直接轉為 SKILL/Rule</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>資源整理型推文，非新觀點，但 everything-claude-code 的規模數字有參考意義</td></tr><tr><td>C. 證據品質 (20%)</td><td>4/10</td><td>僅有 star 數，無使用評測、無 benchmark、無真實案例支撐</td></tr><tr><td>D. 技術深度 (15%)</td><td>3/10</td><td>每個 repo 僅 3 行介紹，無實作細節或架構說明</td></tr><tr><td>E. 泛化性 (15%)</td><td>7/10</td><td>列出的工具（Repomix、claude-squad、security-review）適用多種 workflow 情境</td></tr><tr><td><strong>加權總分</strong></td><td><strong>5.0/10</strong></td><td>6×0.3+5×0.2+4×0.2+3×0.15+7×0.15 = 1.8+1.0+0.8+0.45+1.05 = 5.1</td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：總分 5.1/10，資源整理型列表缺乏可直接轉化為 SKILL/Rule 的實質內容，歸檔備查即可；若後續深入研究特定 repo（如 everything-claude-code 或 anthropics/skills）可另起研究任務。</p>',61)])])}const g=t(o,[["render",i]]);export{u as __pageData,g as default};
